INSERT INTO public.imported_contractors (first_name, last_name, job_title, company, personal_email, work_email, work_email_status, work_email_quality, work_email_confidence, primary_work_email_source, work_email_service_provider, catch_all_status, person_address, country, seniority, departments, personal_linkedin, profile_summary, company_linkedin, industries, company_summary, company_keywords, website, num_employees, phone, company_address, company_city, company_state, company_country, company_phone, company_email, technologies, latest_funding, latest_funding_amount, last_raised_at, facebook, twitter, youtube, instagram, annual_revenue) VALUES
  (E'Billy', E'Helvey', E'Owner', E'Benitz Service Company', NULL, E'billy@benitzservco.com', E'good', E'ok', E'99%', E'A-Leads', NULL, NULL, E'Sedalia, Missouri, United States', E'United States', E'Owner', E'C-Suite', E'https://www.linkedin.com/in/billy-helvey-24aa1772', E'Starting my career selling cars at 19 while in college, I quickly realized my knack for understanding people and building connections. With a Bachelor''s in Marketing and a Master''s in Ethical Strategic Leadership from the University of Central Missouri, I expected these degrees to open doors easily. Ironically, I found myself overqualified and facing more hurdles than anticipated, which taught me resilience and adaptability. My sales journey has been diverse, from winning national sales competitions in college to becoming the youngest territory manager in school photography sales. After relocating to Springfield, MO, I turned a struggling territory profitable within my first year, fueling my passion for transforming challenges into opportunities. In 2019, I transitioned to financial advising with Edward Jones, tripling the size of a small book of business within 11 months. The COVID-19 pandemic posed unforeseen challenges, particularly in maintaining client relationships. This led me to pivot to health insurance for a few years until I found my true calling in real estate and investment. My interest in real estate began in 2015 through the Bigger Pockets podcast and books. I bought my first duplex in 2016, living in one side while renting out the other. Despite a tumultuous 2018—marked by a move, job change, and divorce—I emerged stronger, selling my properties to meet financial obligations and focusing on rebuilding. Now, as the Vice President of Investor Relations at Ingram Capital, I bring my diverse experiences together. Partnering with Bryant Dawson, whom I met through Bigger Pockets, we focus on acquiring car washes, multifamily properties, shopping centers, and other cash-flowing businesses, ensuring robust returns for our investors. In addition to my role at Ingram Capital, I co-founded Contractors, Closers, and Connections (CCC) in Kansas City and Northwest Arkansas, creating meaningful, results-driven connections. Currently, I''m writing a book on using self-directed IRAs to invest in commercial real estate, aiming to empower others with the knowledge to achieve financial independence. Having started from scratch twice, I understand the value of perseverance and smart investing. I''m passionate about helping others achieve financial freedom through strategic investments and lasting partnerships.', E'https://www.linkedin.com/company/benitz-service-company', E'Repair and Maintenance', E'HVAC, Plumbing and Electrical', NULL, E'https://www.benitzservicecompany.com', E'2-10 employees', NULL, E'Sedalia, Missouri, United States', E'Sedalia', E'Missouri', E'United States', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
  (E'Michael', E'Weaver', E'Senior Marketing Consultant', E'The Metal Roof Co., Inc', NULL, E'michael.weaver@themetalroofcompany.com', E'good', E'ok', E'99%', E'A-Leads', NULL, NULL, E'Columbus, Ohio, United States', E'United States', E'Senior', E'Marketing', E'https://www.linkedin.com/in/michael-douglas-weaver-6a01498a', E'I was born and raised in York, Pennsylvania, I currently and for the past 5 years dwell in Columbus, Ohio. I graduated from The Pennsylvania State University, where I earned a hybrid degree in Psychology and Quantitative Analysis. As a self-taught IT professional, I began coding and developing data solutions at the age of 8, building a lifelong foundation in technology and problem-solving. I’ve been a marketing strategist and executive manager, with a unique blend of expertise in data analysis, IT, social networking, and operations management. My background includes designing data-driven marketing strategies that boost engagement and visibility, alongside senior-level data analytics skills that allow me to interpret complex market trends, optimize campaigns, and develop effective tracking tools. I’m adept at cross-functional communication, speaking the "languages" of artists, technologists, and business leaders to align diverse teams around common goals. My IT skills encompass database management, API integration, and workflow automation, which help me ensure seamless data integration across platforms. As a seasoned social networker, I actively build and engage communities online and offline, fostering connections that drive brand loyalty and growth. With a hands-on leadership approach, I excel in executive management, guiding passionate teams and implementing strategic, results-oriented initiatives that bring together creative vision and technical insight. In addition to my marketing and leadership skills, I’ve built a suite of powerful tools tailored to optimize workflows and data handling. My lead tracking engine and custom CRM, developed in VBA, enable efficient management and tracking of client interactions and performance metrics, tailored to align with business needs. This helps me to serve smaller businesses with smaller budgets. I’ve also created advanced financial parsers that categorize and code transactions with precision, speeding up financial processes and improving data integrity for audits and tax preparation. These tools integrate seamlessly across platforms, supporting dynamic and scalable solutions that enhance operations. My focus on building these systems has equipped me to automate complex tasks, allowing teams to make data-driven decisions faster and with greater confidence.', E'https://www.linkedin.com/company/the-metal-roof-co.-inc', NULL, NULL, E'[''construction/building materials'', ''asphalt roofing'', ''roof installation'', ''metal roofing'', ''storm damage evaluation'', ''roof repair evaluation'', ''construction'', ''home improvement'', ''home renovation'']', E'https://www.themetalroofcompany.com', NULL, NULL, E'Westerville, Ohio, United States', E'Westerville', E'Ohio', E'United States', E'[''1 614-721-7663'', ''(614) 721-7663'']', E'[''info@themetalroofcompany.com'']', E'[''bing ads'', ''google ads'', ''facebook'', ''instagram'', ''c'']', NULL, NULL, NULL, E'https://www.facebook.com/themetalroofcompany', NULL, E'https://www.youtube.com/channel/uc2ttbybnb2jfmszfrwsdbxq', E'https://www.instagram.com/metalroofcompany', NULL),
