  (E'Gayle', E'Patrick', E'President', E'Dryer Vent Wizard of Hampton Roads', NULL, E'gpatrick@dryerventwizard.com', E'good', E'ok', E'99%', E'A-Leads', NULL, NULL, E'Newport News, Virginia, United States', E'United States', E'President/Vice President', E'C-Suite', E'https://www.linkedin.com/in/gayle-chong-patrick-83723510', NULL, E'https://www.linkedin.com/company/dryer-vent-wizard-of-hampton-roads', E'Facilities Services', E'Locally owned and operated company with sole focus on Dryer Ventilation Systems. Resident experts on Cleaning, Repairing and Installing Dryer Vents for both Residential and Commercial properties. 

