  (E'Scott', E'Bernhardt', E'Owner', E'SGB Custom Painting', NULL, E'scott@sgbpainting.com', E'good', E'ok', E'99%', E'A-Leads', NULL, NULL, E'Chico, California, United States', E'United States', E'Owner', E'C-Suite', E'https://www.linkedin.com/in/scott-bernhardt-6683048', E'For over 25 years, SGB Custom Painting has been the trusted, go-to painting contractor…', E'https://www.linkedin.com/company/sgb-custom-painting', E'Paint, Coating, and Adhesive Manufacturing', E'For over 25 years, SGB Custom Painting has been the trusted, go-to painting contractor for homeowners, businesses, and property managers throughout Chico and all of Butte County.

