  (E'Brandon', E'Schoen', E'Owner Sandia Green Clean', E'SandiaGreenClean', NULL, E'bschoen@sandiagreenclean.com', E'good', E'ok', E'99%', E'A-Leads', NULL, NULL, E'Albuquerque, New Mexico, United States', E'United States', E'Specialist', E'Other', E'https://www.linkedin.com/in/brandoneschoen', E'I help turn big ideas into thriving businesses. As a serial entrepreneur, I built an…', E'https://www.linkedin.com/company/sandiagreenclean', E'Consumer Services', E'Your home is your sanctuary.

