ation.', E'https://www.linkedin.com/company/eagle-demolition', E'Building Materials', NULL, E'[''industry: n/a'', ''electronics'', ''optoelectronics'', ''custom manufacturer'', ''signage'', ''displays'', ''tft liquid crystal display'']', E'https://www.eagledemolition.com', E'2-10 employees', NULL, E'Long Island City, New York, United States', E'Long Island City', E'New York', E'United States', E'[''805-729-5202'', ''805-729-5201'', ''(805)884-8401'', ''(805) 8840'', ''(805)884-8400'', ''(805) 884-8400'', ''805-729-5200'']', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL),
