  (E'Kory', E'Kettman', E'Owner', E'Kettman Heating and Plumbing', NULL, E'kory@kettmanheating.com', E'good', E'ok', E'99%', E'A-Leads', NULL, NULL, E'Ottawa, Illinois, United States', E'United States', E'Owner', E'C-Suite', E'https://www.linkedin.com/in/kory-kettman-61487aa4', NULL, E'https://www.linkedin.com/company/kettman-heating-and-plumbing', E'Retail Office Equipment', E'Kettman offers qualified technicians on call 24 hours a day, 7 days a week. Anytime day or night, simply call our regular business phone and expect to talk to a real person, not a machine.

